import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, tfm, pkg['id'])
                result[key] = (pkg.get('requestedVersion',''), pkg.get('resolvedVersion',''))
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    proj, tfm, pkg = k
    bv = b.get(k, (None, None))
    av = a.get(k, (None, None))
    if bv[1] != av[1]:
        changes.append((proj, tfm, pkg, bv[1] or 'N/A', av[1] or 'N/A'))
    elif bv != av:
        changes.append((proj, tfm, pkg, f"{bv[0]}->{bv[1]}", f"{av[0]}->{av[1]}"))
    else:
        unchanged.append((proj, tfm, pkg, av[1]))

if changes:
    print("=== CHANGES ===")
    print(f"{'Project':<15} {'TFM':<8} {'Package':<45} {'Before':<12} {'After':<12}")
    for c in changes:
        print(f"{c[0]:<15} {c[1]:<8} {c[2]:<45} {c[3]:<12} {c[4]:<12}")
else:
    print("=== NO VERSION CHANGES ===")

print()
print("=== UNCHANGED ===")
print(f"{'Project':<15} {'TFM':<8} {'Package':<45} {'Version':<12}")
for u in unchanged:
    print(f"{u[0]:<15} {u[1]:<8} {u[2]:<45} {u[3]:<12}")
